-- math: Counting to 120
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Counting to 120", "body": "Count forward and find what number comes next, all the way to 120."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  What number comes next?  25, 26, ___\n\nThe answer is \"27\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  What number comes right after 97?\n\nThe answer is \"98\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  What number comes next?  102, 103, ___\n\nThe answer is \"104\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  What number comes next?  28, 29, ___\n\nThe answer is 30."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  What number comes right after 51?\n\nThe answer is 52."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  What number comes next?  82, 83, ___\n\nThe answer is 84."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Counting to 120! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
