update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Comparing Numbers", "body": "Compare two numbers to tell which one is bigger (greater) or smaller (less)."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which number is bigger: 37 or 43?\n\nThe answer is \"43\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which number is bigger: 19 or 4?\n\nThe answer is \"19\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which number is bigger: 14 or 21?\n\nThe answer is \"21\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which number is bigger: 90 or 5?", "choices": [{"id": "a", "label": "5"}, {"id": "b", "label": "They are equal"}, {"id": "c", "label": "95"}, {"id": "d", "label": "90"}], "answer": "d", "explanation": "Yes! The answer is \"90\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which number is bigger: 46 or 49?", "choices": [{"id": "a", "label": "46"}, {"id": "b", "label": "They are equal"}, {"id": "c", "label": "49"}, {"id": "d", "label": "95"}], "answer": "c", "explanation": "Yes! The answer is \"49\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which number is bigger: 12 or 74?", "choices": [{"id": "a", "label": "12"}, {"id": "b", "label": "They are equal"}, {"id": "c", "label": "74"}, {"id": "d", "label": "86"}], "answer": "c", "explanation": "Yes! The answer is \"74\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Comparing Numbers! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
