update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Telling Time (Hour)", "body": "When the big hand points to 12 and the little hand points to a number, it is that o'clock."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A clock's big hand points to 12 and the little hand points to 8. What time is it?\n\nThe answer is \"8:00\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A clock's big hand points to 12 and the little hand points to 11. What time is it?\n\nThe answer is \"11:00\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A clock's big hand points to 12 and the little hand points to 6. What time is it?\n\nThe answer is \"6:00\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A clock's big hand points to 12 and the little hand points to 4. What time is it?", "choices": [{"id": "a", "label": "4:00"}, {"id": "b", "label": "8:00"}, {"id": "c", "label": "3:00"}, {"id": "d", "label": "6:00"}], "answer": "a", "explanation": "Yes! The answer is \"4:00\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A clock's big hand points to 12 and the little hand points to 1. What time is it?", "choices": [{"id": "a", "label": "2:00"}, {"id": "b", "label": "10:00"}, {"id": "c", "label": "8:00"}, {"id": "d", "label": "1:00"}], "answer": "d", "explanation": "Yes! The answer is \"1:00\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A clock's big hand points to 12 and the little hand points to 11. What time is it?", "choices": [{"id": "a", "label": "7:00"}, {"id": "b", "label": "11:00"}, {"id": "c", "label": "8:00"}, {"id": "d", "label": "2:00"}], "answer": "b", "explanation": "Yes! The answer is \"11:00\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Telling Time (Hour)! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
