update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: How Animals Survive", "body": "Animals need food, water, air, and shelter, and they have ways to stay safe."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Animals need food, water, air, and ____ to live.\n\nThe answer is \"shelter (a safe place)\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A bird builds a nest to:\n\nThe answer is \"keep its eggs and babies safe\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Many animals hide or use camouflage to:\n\nThe answer is \"stay safe from predators\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "In winter, some animals grow thicker fur to:", "choices": [{"id": "a", "label": "stay warm"}, {"id": "b", "label": "swim faster"}, {"id": "c", "label": "fly"}, {"id": "d", "label": "sing"}], "answer": "a", "explanation": "Yes! The answer is \"stay warm\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Bees and ants live together in groups to help each other:", "choices": [{"id": "a", "label": "survive"}, {"id": "b", "label": "watch TV"}, {"id": "c", "label": "play tag"}, {"id": "d", "label": "sleep all year"}], "answer": "a", "explanation": "Yes! The answer is \"survive\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A turtle hides in its shell when it feels:", "choices": [{"id": "a", "label": "happy"}, {"id": "b", "label": "hungry only"}, {"id": "c", "label": "scared or in danger"}, {"id": "d", "label": "sleepy"}], "answer": "c", "explanation": "Yes! The answer is \"scared or in danger\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about How Animals Survive! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
