update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Day & Night Sky", "body": "In the day we see the Sun; at night we see the Moon and stars, in a daily pattern."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which do we see in the sky during the DAY?\n\nThe answer is \"the Sun\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which do we usually see in the sky at NIGHT?\n\nThe answer is \"the Moon and stars\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  The Sun gives Earth:\n\nThe answer is \"light and warmth\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Stars look tiny because they are:", "choices": [{"id": "a", "label": "very small rocks"}, {"id": "b", "label": "made of paper"}, {"id": "c", "label": "very far away"}, {"id": "d", "label": "close to us"}], "answer": "c", "explanation": "Yes! The answer is \"very far away\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Day and night happen in a:", "choices": [{"id": "a", "label": "repeating pattern"}, {"id": "b", "label": "random way"}, {"id": "c", "label": "one-time event"}, {"id": "d", "label": "sound"}], "answer": "a", "explanation": "Yes! The answer is \"repeating pattern\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "When it is daytime, the sky is usually:", "choices": [{"id": "a", "label": "dark"}, {"id": "b", "label": "full of stars"}, {"id": "c", "label": "bright"}, {"id": "d", "label": "green"}], "answer": "c", "explanation": "Yes! The answer is \"bright\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Day & Night Sky! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
