update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Sun & Seasons", "body": "The seasons change in a pattern, with more daylight in summer and less in winter."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which season is usually the coldest?\n\nThe answer is \"winter\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which season is usually the hottest?\n\nThe answer is \"summer\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  In which season do many flowers bloom and trees grow new leaves?\n\nThe answer is \"spring\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "In which season do leaves often turn colors and fall?", "choices": [{"id": "a", "label": "spring"}, {"id": "b", "label": "fall (autumn)"}, {"id": "c", "label": "summer"}, {"id": "d", "label": "winter"}], "answer": "b", "explanation": "Yes! The answer is \"fall (autumn)\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "In summer there are more hours of:", "choices": [{"id": "a", "label": "daylight"}, {"id": "b", "label": "darkness"}, {"id": "c", "label": "snow"}, {"id": "d", "label": "rain only"}], "answer": "a", "explanation": "Yes! The answer is \"daylight\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "In winter there are fewer hours of:", "choices": [{"id": "a", "label": "daylight"}, {"id": "b", "label": "nighttime"}, {"id": "c", "label": "wind"}, {"id": "d", "label": "clouds"}], "answer": "a", "explanation": "Yes! The answer is \"daylight\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Sun & Seasons! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
