update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Main Topic", "body": "The main topic is what a story or text is mostly about."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"My dog can run, jump, and catch a ball.\" This is mostly about:\n\nThe answer is \"what my dog can do\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Bees make honey. They visit many flowers.\" This is mostly about:\n\nThe answer is \"bees\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"I like to swim. The water is cool and fun.\" This is mostly about:\n\nThe answer is \"swimming\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The sun is hot. It gives us light in the day.\" This is mostly about:", "choices": [{"id": "a", "label": "the sun"}, {"id": "b", "label": "the moon"}, {"id": "c", "label": "a cat"}, {"id": "d", "label": "a hat"}], "answer": "a", "explanation": "Yes! The answer is \"the sun\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"We planted seeds. We water them every day.\" This is mostly about:", "choices": [{"id": "a", "label": "a car ride"}, {"id": "b", "label": "growing plants"}, {"id": "c", "label": "a party"}, {"id": "d", "label": "the beach"}], "answer": "b", "explanation": "Yes! The answer is \"growing plants\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Cats like to nap. They sleep a lot in the day.\" This is mostly about:", "choices": [{"id": "a", "label": "dogs running"}, {"id": "b", "label": "a big city"}, {"id": "c", "label": "cats sleeping"}, {"id": "d", "label": "a boat"}], "answer": "c", "explanation": "Yes! The answer is \"cats sleeping\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Main Topic! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
