-- reading: Key Details
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Key Details", "body": "Key details are the small facts in a text that answer who, what, and where."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"Sam has a blue kite.\" What color is the kite?\n\nThe answer is \"blue\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"The cat sat on the soft mat.\" Where did the cat sit?\n\nThe answer is \"on the mat\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"We had grapes for snack.\" What did we eat?\n\nThe answer is \"grapes\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Mia ran fast to the bus.\" How did Mia move?", "choices": [{"id": "a", "label": "slowly"}, {"id": "b", "label": "fast"}, {"id": "c", "label": "backward"}, {"id": "d", "label": "by flying"}], "answer": "b", "explanation": "Yes! The answer is \"fast\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Dad read three books.\" How many books?", "choices": [{"id": "a", "label": "three"}, {"id": "b", "label": "one"}, {"id": "c", "label": "five"}, {"id": "d", "label": "ten"}], "answer": "a", "explanation": "Yes! The answer is \"three\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The dog hid under the bed.\" Where did the dog hide?", "choices": [{"id": "a", "label": "in a tree"}, {"id": "b", "label": "on the roof"}, {"id": "c", "label": "in a box"}, {"id": "d", "label": "under the bed"}], "answer": "d", "explanation": "Yes! The answer is \"under the bed\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Key Details! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$key-details$tl$ and t.grade_level = 1);

-- reading: Retelling & Order
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Retelling & Order", "body": "Retelling means saying what happened first, next, and last, in order."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"First Ana woke up. Then she ate. Last she went to school.\" What did Ana do FIRST?\n\nThe answer is \"woke up\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"The seed grew. Then it had leaves. Last it bloomed.\" What happened LAST?\n\nThe answer is \"it bloomed\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"We packed a bag. Then we drove. Last we played.\" What happened SECOND?\n\nThe answer is \"we drove\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"He woke up, brushed his teeth, then ate.\" What did he do right BEFORE eating?", "choices": [{"id": "a", "label": "went to bed"}, {"id": "b", "label": "ran outside"}, {"id": "c", "label": "read a book"}, {"id": "d", "label": "brushed his teeth"}], "answer": "d", "explanation": "Yes! The answer is \"brushed his teeth\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"First it rained. Then the sun came out. Last we saw a rainbow.\" What came FIRST?", "choices": [{"id": "a", "label": "the rainbow"}, {"id": "b", "label": "it rained"}, {"id": "c", "label": "the sun set"}, {"id": "d", "label": "the snow"}], "answer": "b", "explanation": "Yes! The answer is \"it rained\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Mia drew a cat, colored it, and hung it up.\" What did Mia do LAST?", "choices": [{"id": "a", "label": "hung it up"}, {"id": "b", "label": "drew a cat"}, {"id": "c", "label": "colored it"}, {"id": "d", "label": "erased it"}], "answer": "a", "explanation": "Yes! The answer is \"hung it up\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Retelling & Order! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$retelling-stories$tl$ and t.grade_level = 1);

-- reading: Characters
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Characters", "body": "Characters are the people or animals a story is about."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"Kind Mia helped the lost puppy.\" Who is the character?\n\nThe answer is \"Mia\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Brave Leo climbed the tall hill.\" What word describes Leo?\n\nThe answer is \"brave\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"Grumpy Mr. Fox frowned all day.\" How does Mr. Fox feel?\n\nThe answer is \"grumpy\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Happy Ana danced and smiled.\" How does Ana feel?", "choices": [{"id": "a", "label": "happy"}, {"id": "b", "label": "sad"}, {"id": "c", "label": "angry"}, {"id": "d", "label": "scared"}], "answer": "a", "explanation": "Yes! The answer is \"happy\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The puppy named Bo wagged his tail.\" Who is the character?", "choices": [{"id": "a", "label": "a tree"}, {"id": "b", "label": "the sky"}, {"id": "c", "label": "a rock"}, {"id": "d", "label": "Bo the puppy"}], "answer": "d", "explanation": "Yes! The answer is \"Bo the puppy\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Shy Sam hid behind his mom.\" What word describes Sam?", "choices": [{"id": "a", "label": "loud"}, {"id": "b", "label": "brave"}, {"id": "c", "label": "shy"}, {"id": "d", "label": "silly"}], "answer": "c", "explanation": "Yes! The answer is \"shy\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Characters! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
