update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Opposites", "body": "Opposites are words that mean very different things, like big and small."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  What is the opposite of BIG?\n\nThe answer is \"small\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  What is the opposite of HOT?\n\nThe answer is \"cold\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  What is the opposite of UP?\n\nThe answer is \"down\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "What is the opposite of DAY?", "choices": [{"id": "a", "label": "noon"}, {"id": "b", "label": "sun"}, {"id": "c", "label": "night"}, {"id": "d", "label": "sky"}], "answer": "c", "explanation": "Yes! The answer is \"night\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "What is the opposite of HAPPY?", "choices": [{"id": "a", "label": "glad"}, {"id": "b", "label": "sad"}, {"id": "c", "label": "silly"}, {"id": "d", "label": "kind"}], "answer": "b", "explanation": "Yes! The answer is \"sad\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "What is the opposite of FAST?", "choices": [{"id": "a", "label": "quick"}, {"id": "b", "label": "tall"}, {"id": "c", "label": "big"}, {"id": "d", "label": "slow"}], "answer": "d", "explanation": "Yes! The answer is \"slow\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Opposites! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
