-- reading: Word Meaning
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Word Meaning", "body": "Use the other words in a sentence to figure out what a word means."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"The tiny ant was so small I could hardly see it.\" What does \"tiny\" mean?\n\nThe answer is \"very small\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"I was so tired I fell asleep right away.\" What does \"tired\" mean?\n\nThe answer is \"sleepy\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"The soup was hot, so I let it cool.\" What does \"hot\" mean here?\n\nThe answer is \"very warm\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The huge dog was bigger than me!\" What does \"huge\" mean?", "choices": [{"id": "a", "label": "very small"}, {"id": "b", "label": "very quiet"}, {"id": "c", "label": "very fast"}, {"id": "d", "label": "very big"}], "answer": "d", "explanation": "Yes! The answer is \"very big\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"It was quiet; no one made a sound.\" What does \"quiet\" mean?", "choices": [{"id": "a", "label": "very loud"}, {"id": "b", "label": "very bright"}, {"id": "c", "label": "very cold"}, {"id": "d", "label": "no sound"}], "answer": "d", "explanation": "Yes! The answer is \"no sound\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The happy baby giggled and smiled.\" What does \"happy\" mean?", "choices": [{"id": "a", "label": "sad"}, {"id": "b", "label": "angry"}, {"id": "c", "label": "glad"}, {"id": "d", "label": "sleepy"}], "answer": "c", "explanation": "Yes! The answer is \"glad\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Word Meaning! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$context-clues$tl$ and t.grade_level = 1);

-- reading: Cause & Effect
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Cause & Effect", "body": "A cause is why something happens; the effect is what happens."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"It rained, so we went inside.\" Why did they go inside?\n\nThe answer is \"because it rained\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Sam dropped the cup, so it broke.\" What happened to the cup?\n\nThe answer is \"it broke\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"The dog was hungry, so it barked at its bowl.\" Why did the dog bark?\n\nThe answer is \"it was hungry\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"She watered the plant, so it grew.\" Why did the plant grow?", "choices": [{"id": "a", "label": "she watered it"}, {"id": "b", "label": "it was dark"}, {"id": "c", "label": "it was cold"}, {"id": "d", "label": "nobody touched it"}], "answer": "a", "explanation": "Yes! The answer is \"she watered it\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The ice got hot, so it melted.\" Why did the ice melt?", "choices": [{"id": "a", "label": "it got cold"}, {"id": "b", "label": "it was night"}, {"id": "c", "label": "it was tiny"}, {"id": "d", "label": "it got hot"}], "answer": "d", "explanation": "Yes! The answer is \"it got hot\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Ben was sleepy, so he went to bed.\" Why did Ben go to bed?", "choices": [{"id": "a", "label": "he was sleepy"}, {"id": "b", "label": "he was hungry"}, {"id": "c", "label": "he was happy"}, {"id": "d", "label": "it was morning"}], "answer": "a", "explanation": "Yes! The answer is \"he was sleepy\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Cause & Effect! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$cause-and-effect$tl$ and t.grade_level = 1);

