-- writing: Past-Tense Verbs
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Past-Tense Verbs", "body": "Past-tense verbs tell about something that already happened."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  What is the past tense of the verb \"run\"?\n\nThe answer is \"ran\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  What is the past tense of the verb \"eat\"?\n\nThe answer is \"ate\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  What is the past tense of the verb \"catch\"?\n\nThe answer is \"caught\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  What is the past tense of the verb \"give\"?\n\nThe answer is gave."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  What is the past tense of the verb \"throw\"?\n\nThe answer is threw."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  What is the past tense of the verb \"ride\"?\n\nThe answer is rode."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Past-Tense Verbs! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$writing$tl$ and t.slug = $tl$past-tense-verbs$tl$ and t.grade_level = 1);

-- writing: Plural Nouns
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Plural Nouns", "body": "Plurals mean more than one. Add -s or -es to most nouns."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Write the plural of \"brush\".\n\nThe answer is \"brushes\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Write the plural of \"knife\".\n\nThe answer is \"knives\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Write the plural of \"leaf\".\n\nThe answer is \"leaves\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Write the plural of \"lady\".\n\nThe answer is ladies."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Write the plural of \"fairy\".\n\nThe answer is fairies."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Write the plural of \"wish\".\n\nThe answer is wishes."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Plural Nouns! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
